import { Facility } from '@/types';
import { MapPin, Star, CheckCircle2, Phone, ArrowUpRight } from 'lucide-react';
import Link from 'next/link';

interface FacilityCardProps {
  facility: Facility;
}

export default function FacilityCard({ facility }: FacilityCardProps) {
  const activeFeatures = Object.entries(facility.accessibility_features)
    .filter(([_, value]) => value)
    .slice(0, 3);

  return (
    <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden hover:shadow-xl transition-all group flex flex-col h-full">
      <div className="relative h-48 overflow-hidden">
        <img 
          src={facility.photos[0]} 
          alt={facility.name}
          className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
        />
        <div className="absolute top-4 right-4 bg-white/90 backdrop-blur-md px-3 py-1 rounded-full text-xs font-bold flex items-center shadow-sm">
          <Star className="text-yellow-500 mr-1 fill-yellow-500" size={12} />
          {facility.rating}
        </div>
        <div className={`absolute bottom-4 left-4 px-3 py-1 rounded-full text-xs font-bold text-white shadow-lg ${
          facility.accessibility_score > 80 ? 'bg-green-600' : 
          facility.accessibility_score > 50 ? 'bg-yellow-600' : 'bg-red-600'
        }`}>
          Score: {facility.accessibility_score}%
        </div>
      </div>

      <div className="p-5 flex flex-col flex-grow">
        <div className="flex justify-between items-start mb-2">
          <h3 className="text-lg font-bold text-slate-900 group-hover:text-primary-600 transition-colors">
            {facility.name}
          </h3>
          {facility.verified && (
            <CheckCircle2 className="text-accent-600 shrink-0" size={18} aria-label="Verified Facility" />
          )}
        </div>

        <div className="flex items-start gap-1 text-slate-500 text-sm mb-4">
          <MapPin size={14} className="mt-1 shrink-0" />
          <span className="line-clamp-1">{facility.address}</span>
        </div>

        <div className="space-y-2 mb-6 flex-grow">
          {activeFeatures.map(([key, _]) => (
            <div key={key} className="flex items-center gap-2 text-xs text-slate-600 bg-slate-50 px-3 py-1.5 rounded-lg border border-slate-100">
              <CheckCircle2 size={12} className="text-accent-500" />
              <span className="capitalize">{key.replace(/_/g, ' ')}</span>
            </div>
          ))}
          {Object.values(facility.accessibility_features).filter(Boolean).length > 3 && (
            <div className="text-[10px] text-slate-400 font-medium pl-2">
              + {Object.values(facility.accessibility_features).filter(Boolean).length - 3} more features
            </div>
          )}
        </div>

        <div className="flex items-center gap-3 pt-4 border-t border-slate-100 mt-auto">
          <Link 
            href={`/facilities/${facility.id}`}
            className="flex-grow bg-slate-900 text-white text-center py-2.5 rounded-xl font-bold text-sm hover:bg-primary-600 transition-all flex items-center justify-center gap-2"
          >
            View Details
            <ArrowUpRight size={16} />
          </Link>
          <a 
            href={`tel:${facility.contact}`}
            className="p-2.5 bg-slate-100 text-slate-600 rounded-xl hover:bg-slate-200 transition-all"
            aria-label="Call facility"
          >
            <Phone size={18} />
          </a>
        </div>
      </div>
    </div>
  );
}
