"use client";
import { useState, useEffect } from 'react';
import Navbar from '@/components/layout/Navbar';
import FacilityCard from '@/components/facility/FacilityCard';
import { generateMockFacilities } from '@/lib/mockData';
import { Facility, AccessibilityFeature } from '@/types';
import { Filter, Map as MapIcon, List, Search as SearchIcon, SlidersHorizontal, ChevronDown } from 'lucide-react';

const ACCESSIBILITY_LABELS: Record<AccessibilityFeature, string> = {
  wheelchair_ramp: 'Wheelchair Ramp',
  elevator: 'Elevator',
  accessible_restroom: 'Accessible Restroom',
  braille_signage: 'Braille Signage',
  tactile_path: 'Tactile Path',
  wide_doorway: 'Wide Doorway',
  adjustable_exam_table: 'Adjustable Exam Table',
  sign_language_interpreter: 'Sign Language Interpreter',
  priority_queue: 'Priority Queue',
  disabled_parking: 'Disabled Parking'
};

export default function SearchPage() {
  const [facilities, setFacilities] = useState<Facility[]>([]);
  const [filteredFacilities, setFilteredFacilities] = useState<Facility[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [activeFilters, setActiveFilters] = useState<AccessibilityFeature[]>([]);
  const [viewMode, setViewMode] = useState<'list' | 'map'>('list');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  useEffect(() => {
    console.log("Initializing facilities...");
    try {
      const data = generateMockFacilities(50);
      console.log(`Generated ${data.length} facilities.`);
      setFacilities(data);
      setFilteredFacilities(data);
    } catch (err) {
      console.error("Failed to generate facilities:", err);
    }
  }, []);

  useEffect(() => {
    let result = facilities;

    if (searchQuery) {
      result = result.filter(f => 
        f.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
        f.address.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }

    if (activeFilters.length > 0) {
      result = result.filter(f => 
        activeFilters.every(filter => f.accessibility_features[filter])
      );
    }

    setFilteredFacilities(result);
  }, [searchQuery, activeFilters, facilities]);

  const toggleFilter = (filter: AccessibilityFeature) => {
    setActiveFilters(prev => 
      prev.includes(filter) ? prev.filter(f => f !== filter) : [...prev, filter]
    );
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Navbar />
      
      <div className="flex-grow flex overflow-hidden">
        {/* Sidebar Filters */}
        <aside className={`${isSidebarOpen ? 'w-80' : 'w-0'} bg-white border-r border-slate-200 transition-all duration-300 overflow-y-auto hidden md:block`}>
          <div className="p-6">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-slate-900 flex items-center gap-2">
                <SlidersHorizontal size={20} className="text-primary-600" />
                Filters
              </h2>
              <button 
                onClick={() => setActiveFilters([])}
                className="text-xs text-primary-600 font-bold hover:underline"
              >
                Reset All
              </button>
            </div>

            <div className="space-y-6">
              <div>
                <h3 className="text-sm font-bold text-slate-800 mb-3 uppercase tracking-wider">Accessibility Needs</h3>
                <div className="space-y-2">
                  {(Object.keys(ACCESSIBILITY_LABELS) as AccessibilityFeature[]).map(key => (
                    <label key={key} className="flex items-center gap-3 cursor-pointer group">
                      <div className="relative flex items-center">
                        <input 
                          type="checkbox" 
                          checked={activeFilters.includes(key)}
                          onChange={() => toggleFilter(key)}
                          className="w-5 h-5 rounded border-slate-300 text-primary-600 focus:ring-primary-500 transition-all"
                        />
                      </div>
                      <span className={`text-sm transition-colors ${activeFilters.includes(key) ? 'text-primary-700 font-bold' : 'text-slate-600 font-medium'}`}>
                        {ACCESSIBILITY_LABELS[key]}
                      </span>
                    </label>
                  ))}
                </div>
              </div>

              <div className="pt-6 border-t border-slate-100">
                <h3 className="text-sm font-bold text-slate-800 mb-3 uppercase tracking-wider">Distance Radius</h3>
                <select className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary-500">
                  <option>Within 5 km</option>
                  <option>Within 10 km</option>
                  <option>Within 25 km</option>
                  <option>Anywhere</option>
                </select>
              </div>
            </div>
          </div>
        </aside>

        {/* Main Content Area */}
        <main className="flex-grow flex flex-col h-[calc(100vh-64px)] overflow-hidden">
          {/* Top Bar Tooling */}
          <div className="bg-white border-b border-slate-200 p-4 flex flex-col md:flex-row justify-between items-center gap-4">
            <div className="text-sm text-slate-500">
              Showing <span className="font-bold text-slate-900">{filteredFacilities.length}</span> facilities in <span className="font-bold text-slate-900">Mumbai</span>
            </div>
            
            <div className="flex items-center bg-slate-100 p-1 rounded-xl">
              <button 
                onClick={() => setViewMode('list')}
                className={`flex items-center gap-2 px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${viewMode === 'list' ? 'bg-white shadow-sm text-primary-600' : 'text-slate-500 hover:text-slate-700'}`}
              >
                <List size={18} />
                List
              </button>
              <button 
                onClick={() => setViewMode('map')}
                className={`flex items-center gap-2 px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${viewMode === 'map' ? 'bg-white shadow-sm text-primary-600' : 'text-slate-500 hover:text-slate-700'}`}
              >
                <MapIcon size={18} />
                Map
              </button>
            </div>
          </div>

          {/* Results Area */}
          <div className="flex-grow overflow-y-auto p-4 md:p-8">
            {viewMode === 'list' ? (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 max-w-7xl mx-auto">
                {filteredFacilities.map(f => (
                  <FacilityCard key={f.id} facility={f} />
                ))}
                
                {filteredFacilities.length === 0 && (
                  <div className="col-span-full py-20 text-center">
                    <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-400">
                      <SearchIcon size={32} />
                    </div>
                    <h3 className="text-xl font-bold text-slate-900 mb-2">No facilities found</h3>
                    <p className="text-slate-500">Try adjusting your filters or search terms.</p>
                  </div>
                )}
              </div>
            ) : (
              <div className="w-full h-full bg-slate-200 rounded-2xl flex items-center justify-center relative overflow-hidden">
                <div className="absolute inset-0 bg-[url('https://api.mapbox.com/styles/v1/mapbox/light-v10/static/72.87,19.07,11,0/1200x800?access_token=pk.placeholder')] bg-cover opacity-50"></div>
                <div className="relative z-10 text-center p-8 bg-white/80 backdrop-blur-md rounded-2xl shadow-xl max-w-sm">
                  <MapIcon size={48} className="mx-auto text-primary-500 mb-4" />
                  <h3 className="text-lg font-bold text-slate-900 mb-2">Interactive Map</h3>
                  <p className="text-sm text-slate-600 mb-6">
                    In a production environment, this would initialize a Leaflet or Google Maps instance with {filteredFacilities.length} markers.
                  </p>
                  <button className="bg-primary-600 text-white px-6 py-2 rounded-xl font-bold hover:bg-primary-700">
                    Enable High Accuracy GPS
                  </button>
                </div>
              </div>
            )}
          </div>
        </main>
      </div>
    </div>
  );
}
